	}

	if m.Endpoint == "" {
		return fmt.Errorf("MCP tool '%s' must have an endpoint", m.Name)
	}

	// Basic endpoint format validation
	if len(m.Endpoint) < 6 {
		return fmt.Errorf("MCP tool '%s' endpoint is too short", m.Name)
	}

